namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(new[]
        {
            CreateNotification("Welcome to the notification center!"),
            CreateNotification("Your profile was updated successfully."),
            CreateNotification("New feature: dark mode is now available."),
        });
    }

    public List<Notification> GetNotifications()
    {
        lock (_lock)
        {
            return _notifications.OrderByDescending(n => n.Timestamp).ToList();
        }
    }

    /// <summary>
    /// Returns notifications added after the given timestamp.
    /// Simulates a ~30 % chance of generating a new notification each call.
    /// </summary>
    public List<Notification> GetNewNotificationsSince(DateTime since)
    {
        lock (_lock)
        {
            if (Random.Shared.Next(0, 10) < 3)
            {
                var messages = new[]
                {
                    "You have a new follower!",
                    "Your post received a like.",
                    "Server maintenance scheduled for tonight.",
                    "Reminder: team standup in 15 minutes.",
                    "New comment on your pull request.",
                    "Deployment to production completed.",
                };

                _notifications.Add(
                    CreateNotification(messages[Random.Shared.Next(messages.Length)]));
            }

            return _notifications
                .Where(n => n.Timestamp > since)
                .OrderByDescending(n => n.Timestamp)
                .ToList();
        }
    }

    private Notification CreateNotification(string message)
    {
        return new Notification(_nextId++, message, DateTime.UtcNow.AddMilliseconds(_nextId));
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@using BlazorNotifications.Services
@inject NotificationService NotificationSvc
@inject PersistentComponentState ApplicationState

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group mt-3">
        @foreach (var n in notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@if (isPolling)
{
    <p class="mt-3 text-success"><small>🔄 Live — polling for new notifications…</small></p>
}

@code {
    private List<Notification> notifications = new();
    private CancellationTokenSource? cts;
    private PersistingComponentStateSubscription persistingSubscription;
    private bool isPolling;

    protected override void OnInitialized()
    {
        // If persisted state exists (interactive reconnect), reuse it
        // so we don't re-fetch the initial data from the service.
        persistingSubscription = ApplicationState.RegisterOnPersisting(PersistNotifications);

        if (ApplicationState.TryTakeFromJson<List<Notification>>(
                "notifications", out var restored))
        {
            notifications = restored!;
        }
        else
        {
            // First (SSR) render — load from the service.
            notifications = NotificationSvc.GetNotifications();
        }
    }

    private Task PersistNotifications()
    {
        ApplicationState.PersistAsJson("notifications", notifications);
        return Task.CompletedTask;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // OnAfterRender only fires when the component is interactive,
        // never during static SSR — safe to start the polling loop here.
        if (firstRender)
        {
            cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(cts.Token);
        }

        await Task.CompletedTask;
    }

    private async Task PollForNotificationsAsync(CancellationToken token)
    {
        isPolling = true;
        await InvokeAsync(StateHasChanged);

        while (!token.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), token);

                var since = notifications.Count > 0
                    ? notifications.Max(n => n.Timestamp)
                    : DateTime.MinValue;

                var newer = NotificationSvc.GetNewNotificationsSince(since);

                if (newer.Count > 0)
                {
                    notifications.InsertRange(0, newer);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    public void Dispose()
    {
        persistingSubscription.Dispose();
        cts?.Cancel();
        cts?.Dispose();
    }
}

