namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(new[]
        {
            CreateNotification("Welcome to the notification center!"),
            CreateNotification("Your profile was updated successfully."),
            CreateNotification("New feature: dark mode is now available."),
        });
    }

    public List<Notification> GetNotifications()
    {
        lock (_lock)
        {
            return _notifications.OrderByDescending(n => n.Timestamp).ToList();
        }
    }

    /// <summary>
    /// Returns notifications added after the given timestamp.
    /// Simulates a ~30 % chance of generating a new notification each call.
    /// </summary>
    public List<Notification> GetNewNotificationsSince(DateTime since)
    {
        lock (_lock)
        {
            if (Random.Shared.Next(0, 10) < 3)
            {
                var messages = new[]
                {
                    "You have a new follower!",
                    "Your post received a like.",
                    "Server maintenance scheduled for tonight.",
                    "Reminder: team standup in 15 minutes.",
                    "New comment on your pull request.",
                    "Deployment to production completed.",
                };

                _notifications.Add(
                    CreateNotification(messages[Random.Shared.Next(messages.Length)]));
            }

            return _notifications
                .Where(n => n.Timestamp > since)
                .OrderByDescending(n => n.Timestamp)
                .ToList();
        }
    }

    private Notification CreateNotification(string message)
    {
        return new Notification(_nextId++, message, DateTime.UtcNow.AddMilliseconds(_nextId));
    }
}

